import React, { useEffect, useRef, useState } from "react";
import Client1 from "../assets/favicon.svg";
import Client2 from "../assets/favicon.svg";
import Client3 from "../assets/favicon.svg";
import Client4 from "../assets/favicon.svg";

const icons = [Client1, Client2, Client3, Client4];

const ServiceLogos: React.FC = () => {
  const marqueeRef = useRef<HTMLUListElement>(null);
  const [elementsDisplayed, setElementsDisplayed] = useState(6);

  useEffect(() => {
    const updateDisplayedElements = () => {
      const width = window.innerWidth;
      if (width < 640) {
        setElementsDisplayed(3);
      } else if (width < 768) {
        setElementsDisplayed(4);
      } else if (width < 1024) {
        setElementsDisplayed(5);
      } else {
        setElementsDisplayed(6);
      }
    };

    updateDisplayedElements();
    window.addEventListener("resize", updateDisplayedElements);

    const root = document.documentElement;
    const marqueeContent = marqueeRef.current;

    if (marqueeContent) {
      root.style.setProperty("--marquee-elements", `${icons.length}`);
      root.style.setProperty(
        "--marquee-elements-displayed",
        `${elementsDisplayed}`
      );

      // Clear existing clones
      const existingClones = marqueeContent.querySelectorAll("[data-cloned]");
      existingClones.forEach((clone) => clone.remove());

      // Add new clones
      for (let i = 0; i < elementsDisplayed; i++) {
        const clone = marqueeContent.children[i].cloneNode(true) as HTMLElement;
        clone.setAttribute("data-cloned", "true");
        marqueeContent.appendChild(clone);

        const prependClone = marqueeContent.children[
          icons.length - 1 - i
        ].cloneNode(true) as HTMLElement;
        prependClone.setAttribute("data-cloned", "true");
        marqueeContent.prepend(prependClone);
      }
    }

    return () => {
      window.removeEventListener("resize", updateDisplayedElements);
    };
  }, [elementsDisplayed]);

  return (
    <div className="marquee-service">
      <ul className="marquee-content-service" ref={marqueeRef}>
        {icons.map((icon, index) => (
          <li
            key={index}
            className="bg-[#0c0c0c] rounded-lg flex justify-center items-center p-1 overflow-hidden"
          >
            <img
              src={icon}
              className="rotate-90 w-full h-full object-contain"
              alt={`logo-${index}`}
            />
          </li>
        ))}
      </ul>
    </div>
  );
};

export default ServiceLogos;
